{
  "$schema": "./node_modules/oxlint/configuration_schema.json",
  "plugins": ["react", "typescript", "oxc"],
  "rules": {
    "react/rules-of-hooks": "error",
    "react/only-export-components": ["warn", { "allowConstantExport": true }]
  }
}

{
  "name": "app",
  "private": true,
  "version": "0.0.0",
  "type": "module",
  "scripts": {
    "dev": "vite",
    "build": "tsc -b && vite build",
    "lint": "oxlint",
    "preview": "vite preview"
  },
  "dependencies": {
    "lucide-react": "^1.24.0",
    "react": "^19.2.7",
    "react-dom": "^19.2.7"
  },
  "devDependencies": {
    "@types/node": "^24.13.2",
    "@types/react": "^19.2.17",
    "@types/react-dom": "^19.2.3",
    "@vitejs/plugin-react": "^6.0.3",
    "oxlint": "^1.71.0",
    "typescript": "~6.0.2",
    "vite": "^8.1.1"
  }
}

.counter {
  font-size: 16px;
  padding: 5px 10px;
  border-radius: 5px;
  color: var(--accent);
  background: var(--accent-bg);
  border: 2px solid transparent;
  transition: border-color 0.3s;
  margin-bottom: 24px;

  &:hover {
    border-color: var(--accent-border);
  }
  &:focus-visible {
    outline: 2px solid var(--accent);
    outline-offset: 2px;
  }
}

.hero {
  position: relative;

  .base,
  .framework,
  .vite {
    inset-inline: 0;
    margin: 0 auto;
  }

  .base {
    width: 170px;
    position: relative;
    z-index: 0;
  }

  .framework,
  .vite {
    position: absolute;
  }

  .framework {
    z-index: 1;
    top: 34px;
    height: 28px;
    transform: perspective(2000px) rotateZ(300deg) rotateX(44deg) rotateY(39deg)
      scale(1.4);
  }

  .vite {
    z-index: 0;
    top: 107px;
    height: 26px;
    width: auto;
    transform: perspective(2000px) rotateZ(300deg) rotateX(40deg) rotateY(39deg)
      scale(0.8);
  }
}

#center {
  display: flex;
  flex-direction: column;
  gap: 25px;
  place-content: center;
  place-items: center;
  flex-grow: 1;

  @media (max-width: 1024px) {
    padding: 32px 20px 24px;
    gap: 18px;
  }
}

#next-steps {
  display: flex;
  border-top: 1px solid var(--border);
  text-align: left;

  & > div {
    flex: 1 1 0;
    padding: 32px;
    @media (max-width: 1024px) {
      padding: 24px 20px;
    }
  }

  .icon {
    margin-bottom: 16px;
    width: 22px;
    height: 22px;
  }

  @media (max-width: 1024px) {
    flex-direction: column;
    text-align: center;
  }
}

#docs {
  border-right: 1px solid var(--border);

  @media (max-width: 1024px) {
    border-right: none;
    border-bottom: 1px solid var(--border);
  }
}

#next-steps ul {
  list-style: none;
  padding: 0;
  display: flex;
  gap: 8px;
  margin: 32px 0 0;

  .logo {
    height: 18px;
  }

  a {
    color: var(--text-h);
    font-size: 16px;
    border-radius: 6px;
    background: var(--social-bg);
    display: flex;
    padding: 6px 12px;
    align-items: center;
    gap: 8px;
    text-decoration: none;
    transition: box-shadow 0.3s;

    &:hover {
      box-shadow: var(--shadow);
    }
    .button-icon {
      height: 18px;
      width: 18px;
    }
  }

  @media (max-width: 1024px) {
    margin-top: 20px;
    flex-wrap: wrap;
    justify-content: center;

    li {
      flex: 1 1 calc(50% - 8px);
    }

    a {
      width: 100%;
      justify-content: center;
      box-sizing: border-box;
    }
  }
}

#spacer {
  height: 88px;
  border-top: 1px solid var(--border);
  @media (max-width: 1024px) {
    height: 48px;
  }
}

.ticks {
  position: relative;
  width: 100%;

  &::before,
  &::after {
    content: '';
    position: absolute;
    top: -4.5px;
    border: 5px solid transparent;
  }

  &::before {
    left: 0;
    border-left-color: var(--border);
  }
  &::after {
    right: 0;
    border-right-color: var(--border);
  }
}

import { AppLayout } from "./layouts/AppLayout";

function App() {
  return (
    <AppLayout />
  );
}

export default App;

import React, { useState } from "react";

export const Converter: React.FC = () => {
  const [rawText, setRawText] = useState(`{"id": 125478, "username": "leak.test"}`);
  const [convertedText, setConvertedText] = useState("");
  const [isConverting, setIsConverting] = useState(false);

  const handleConvert = () => {
    setIsConverting(true);
    setTimeout(() => {
      setConvertedText(`[\n  {\n    "id": 125478,\n    "username": "leak.test",\n    "status": "parsed"\n  }\n]`);
      setIsConverting(false);
    }, 600);
  };

  return (
    <div className="reveal">
      <div className="hero-card" style={{ marginBottom: "18px" }}>
        <h1>Конвертер даних (Mock)</h1>
        <p>Перетворення різноманітних SQL, TXT та JSON витоків у стандартизований формат.</p>
      </div>

      <div className="converter">
        <div className="panel code-panel">
          <div className="panel-head">
            <div className="panel-title"><strong>RAW (Сирі дані)</strong></div>
          </div>
          <textarea 
            className="code-box"
            style={{ width: "100%", border: "none", resize: "none" }}
            value={rawText}
            onChange={(e) => setRawText(e.target.value)}
          />
        </div>

        <div className="controls-panel">
          <div className="field">
            <label>Шаблон парсингу</label>
            <select className="select">
              <option>User DB (За замовчуванням)</option>
              <option>Combo List</option>
            </select>
          </div>
          <button className="convert-button" onClick={handleConvert} disabled={isConverting}>
            {isConverting ? "Обробка..." : "Конвертувати"}
          </button>
        </div>

        <div className="panel code-panel">
          <div className="panel-head">
            <div className="panel-title"><strong>Структуровані дані</strong></div>
          </div>
          <textarea 
            className="code-box"
            style={{ width: "100%", border: "none", resize: "none", background: "#fbf6ea", color: "#111" }}
            value={convertedText}
            readOnly
          />
        </div>
      </div>
    </div>
  );
};

import React from "react";
import { Header } from "../Header/Header";
import { StatsSection } from "./StatsSection";
import { MainContent } from "./MainContent";

export const Dashboard: React.FC = () => {
  return (
    <div className="shell reveal">
      <Header />
      <div className="content">
        <StatsSection />
        <MainContent />
      </div>
    </div>
  );
};

import React, { useState } from "react";
import { mockLeaks, formatNumber } from "../../data/mockData";

export const MainContent: React.FC = () => {
  const [leaks] = useState(mockLeaks);

  const getThreatPillClass = (level: string) => {
    switch (level) {
      case "Висока": return "pill bad";
      case "Середня": return "pill mid";
      case "Низька": return "pill good";
      default: return "pill neutral";
    }
  };

  const handleAction = () => {
    alert("Перехід до режиму детального аналізу витоків. (Демо)");
  };

  return (
    <div className="section-grid" style={{ gridTemplateColumns: "1fr" }}>
      <div className="panel" style={{ minHeight: "350px" }}>
        <div className="panel-head">
          <div className="panel-title">
            <strong>Останні активності та Прямі сповіщення</strong>
            <span>Моніторинг в реальному часі</span>
          </div>
          <button className="primary-button" onClick={handleAction}>Переглянути всі</button>
        </div>
        <div className="table-wrap">
          <table>
            <thead>
              <tr>
                <th>Час</th>
                <th>Джерело</th>
                <th>Заголовок</th>
                <th>Тип</th>
                <th>Записи</th>
                <th>Вразливість</th>
                <th>Дії</th>
              </tr>
            </thead>
            <tbody>
              {leaks.map((leak) => (
                <tr key={leak.id}>
                  <td>{leak.time}</td>
                  <td><a href="#" className="source-link">{leak.source}</a></td>
                  <td>{leak.title}</td>
                  <td>{leak.type}</td>
                  <td>{formatNumber(leak.recordsCount)}</td>
                  <td><span className={getThreatPillClass(leak.threatLevel)}>{leak.threatLevel}</span></td>
                  <td><button className="small-button">Аналіз</button></td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      </div>
    </div>
  );
};

export interface GeoDocument {
  id: string;
  name: string;
  type: string;
  size: string;
  uploadedAt: string;
  status: 'Оброблено' | 'В процесі' | 'Помилка';
}

export interface GeoPoint {
  id: string;
  lat: number;
  lng: number;
  sourceDocId: string;
  type: string;
  description: string;
  timestamp: string;
  isFresh: boolean;
}

export interface LeakRecord {
  id: string;
  time: string;
  source: string;
  title: string;
  type: "SQL" | "JSON" | "TXT" | "CSV";
  recordsCount: number;
  threatLevel: "Висока" | "Середня" | "Низька";
}

export const mockLeaks: LeakRecord[] = [
  { id: "1", time: "10:23:11", source: "BreachForums", title: "US Logistics Company DB", type: "SQL", recordsCount: 2340190, threatLevel: "Висока" },
  { id: "2", time: "10:22:45", source: "Telegram Channel", title: "Users DB Dump", type: "SQL", recordsCount: 1982112, threatLevel: "Висока" },
  { id: "3", time: "10:21:02", source: "DarkWeb Forum", title: "Financial Data Pack", type: "SQL", recordsCount: 532198, threatLevel: "Середня" },
  { id: "4", time: "10:19:33", source: "Pastebin", title: "Leaked Customers", type: "JSON", recordsCount: 12532, threatLevel: "Низька" },
  { id: "5", time: "10:18:55", source: "Telegram Channel", title: "Combo List 2025", type: "TXT", recordsCount: 104892, threatLevel: "Середня" },
];

export const formatNumber = (num: number) => new Intl.NumberFormat('en-US').format(num);

      :root {
        --bg: #f7f2e8;
        --bg-2: #f1ffe6;
        --panel: #fffaf2;
        --panel-strong: #ffffff;
        --ink: #121212;
        --muted: #4b4b4b;
        --line: #121212;
        --accent: #ffbf1f;
        --accent-2: #66f0c2;
        --accent-3: #ff6b6b;
        --success: #0f8b5e;
        --warning: #d97706;
        --danger: #dc2626;
        --shadow: 10px 10px 0 var(--line);
        --shadow-soft: 6px 6px 0 var(--line);
        --radius-lg: 22px;
        --radius-md: 16px;
        --radius-sm: 12px;
      }

      * {
        box-sizing: border-box;
      }

      html,
      body,
      #root {
        height: 100%;
        min-height: 100vh;
      }

      body {
        margin: 0;
        color: var(--ink);
        font-family: Inter, system-ui, -apple-system, BlinkMacSystemFont, "Segoe UI", sans-serif;
        background:
          radial-gradient(circle at 12% 10%, rgba(255, 191, 31, 0.55), transparent 18%),
          radial-gradient(circle at 88% 14%, rgba(102, 240, 194, 0.38), transparent 16%),
          radial-gradient(circle at 80% 86%, rgba(255, 107, 107, 0.18), transparent 20%),
          linear-gradient(180deg, var(--bg) 0%, #f8f5ec 48%, var(--bg-2) 100%);
      }

      button,
      select {
        font: inherit;
      }

      .app {
        min-height: 100%;
        display: grid;
        grid-template-columns: 292px minmax(0, 1fr);
      }

      .sidebar {
        position: sticky;
        top: 0;
        height: 100vh;
        overflow: auto;
        padding: 18px 14px;
        background: #111;
        color: #fff7e6;
        border-right: 4px solid var(--line);
      }

      .brand {
        display: flex;
        gap: 12px;
        align-items: center;
        padding: 4px 4px 18px;
      }

      .brand-mark {
        width: 50px;
        height: 50px;
        display: grid;
        place-items: center;
        border: 3px solid #111;
        border-radius: 14px;
        background: var(--accent);
        color: #111;
        font-family: "Space Grotesk", Inter, sans-serif;
        font-size: 22px;
        font-weight: 900;
        box-shadow: 6px 6px 0 rgba(255, 255, 255, 0.08);
      }

      .brand-title strong {
        display: block;
        font-family: "Space Grotesk", Inter, sans-serif;
        font-size: 15px;
        letter-spacing: 0.03em;
      }

      .brand-title span {
        display: block;
        margin-top: 3px;
        font-size: 12px;
        color: rgba(255, 247, 230, 0.68);
      }

      .side-section {
        margin-top: 14px;
      }

      .section-label {
        padding: 10px 10px 8px;
        font-size: 11px;
        text-transform: uppercase;
        letter-spacing: 0.16em;
        color: rgba(255, 247, 230, 0.5);
      }

      .nav-list {
        display: grid;
        gap: 8px;
      }

      .nav-item {
        width: 100%;
        border: 3px solid transparent;
        border-radius: 14px;
        padding: 11px 12px;
        background: #1d1d1d;
        color: inherit;
        display: flex;
        align-items: center;
        justify-content: space-between;
        gap: 10px;
        cursor: pointer;
        transition: transform 140ms ease, box-shadow 140ms ease, background 140ms ease;
      }

      .nav-item:hover {
        transform: translate(-1px, -1px);
        box-shadow: 4px 4px 0 rgba(255, 255, 255, 0.08);
      }

      .nav-item.active {
        background: var(--accent);
        color: #111;
        border-color: #111;
        box-shadow: 5px 5px 0 #fff;
      }

      .nav-left {
        display: flex;
        align-items: center;
        gap: 10px;
      }

      .nav-icon {
        width: 24px;
        height: 24px;
        display: grid;
        place-items: center;
        border-radius: 7px;
        background: rgba(255, 255, 255, 0.08);
        font-size: 12px;
      }

      .nav-item.active .nav-icon {
        background: rgba(17, 17, 17, 0.12);
      }

      .badge {
        min-width: 30px;
        height: 24px;
        padding: 0 8px;
        border: 2px solid #111;
        border-radius: 999px;
        display: inline-flex;
        align-items: center;
        justify-content: center;
        background: #fff;
        color: #111;
        font-size: 12px;
        font-weight: 800;
      }

      .badge.hot {
        background: var(--accent-3);
        color: #111;
      }

      .sidebar-footer {
        margin-top: 18px;
        padding: 14px;
        border: 3px solid #111;
        border-radius: 18px;
        background: linear-gradient(180deg, #222, #181818);
        box-shadow: 6px 6px 0 rgba(255, 255, 255, 0.08);
      }

      .footer-row {
        display: flex;
        justify-content: space-between;
        align-items: center;
        font-size: 12px;
      }

      .footer-meter {
        margin-top: 10px;
        height: 10px;
        background: rgba(255, 255, 255, 0.12);
        border: 2px solid #111;
        border-radius: 999px;
        overflow: hidden;
      }

      .footer-meter > span,
      .bar > span,
      .sys-bar > span {
        display: block;
        height: 100%;
        border-radius: inherit;
        background: linear-gradient(90deg, var(--accent), var(--accent-2));
      }

      .main {
        padding: 18px;
      }

      .shell {
        border: 4px solid #111;
        border-radius: 28px;
        background: rgba(255, 250, 242, 0.92);
        box-shadow: var(--shadow);
        overflow: hidden;
      }

      .topbar {
        display: flex;
        justify-content: space-between;
        gap: 14px;
        align-items: center;
        padding: 16px 18px;
        border-bottom: 4px solid #111;
        background: linear-gradient(180deg, #fffef8, #f7f1e7);
      }

      .topbar-left,
      .topbar-right {
        display: flex;
        align-items: center;
        gap: 10px;
      }

      .status-pill {
        display: inline-flex;
        align-items: center;
        gap: 8px;
        padding: 9px 12px;
        border: 3px solid #111;
        border-radius: 999px;
        background: #fff;
        font-size: 13px;
      }

      .status-dot {
        width: 10px;
        height: 10px;
        border-radius: 999px;
        background: var(--success);
        box-shadow: 0 0 0 4px rgba(15, 139, 94, 0.14);
      }

      .icon-button,
      .text-button,
      .primary-button,
      .secondary-button,
      .link-button,
      .small-button,
      .convert-button {
        border: 3px solid #111;
        border-radius: 14px;
        background: #fff;
        color: #111;
        box-shadow: 4px 4px 0 #111;
        transition: transform 120ms ease, box-shadow 120ms ease;
      }

      .icon-button:hover,
      .text-button:hover,
      .primary-button:hover,
      .secondary-button:hover,
      .link-button:hover,
      .small-button:hover,
      .convert-button:hover {
        transform: translate(-1px, -1px);
        box-shadow: 5px 5px 0 #111;
      }

      .icon-button {
        width: 42px;
        height: 42px;
        display: inline-grid;
        place-items: center;
        padding: 0;
      }

      .text-button {
        height: 42px;
        padding: 0 14px;
        display: inline-flex;
        align-items: center;
        gap: 10px;
        font-weight: 700;
      }

      .pill-alert {
        position: relative;
      }

      .pill-alert::after {
        content: "12";
        position: absolute;
        top: -7px;
        right: -7px;
        min-width: 22px;
        height: 22px;
        border: 2px solid #111;
        border-radius: 999px;
        display: grid;
        place-items: center;
        background: var(--accent-3);
        color: #111;
        font-size: 11px;
        font-weight: 900;
      }

      .content {
        display: grid;
        gap: 18px;
        padding: 18px;
      }

      .hero {
        display: grid;
        grid-template-columns: minmax(0, 1fr) 320px;
        gap: 18px;
      }

      .hero-card,
      .mini-panel,
      .stat-card,
      .panel {
        border: 3px solid #111;
        border-radius: var(--radius-lg);
        background: var(--panel);
        box-shadow: var(--shadow-soft);
      }

      .hero-card {
        padding: 24px;
        background:
          linear-gradient(135deg, rgba(255, 191, 31, 0.24), transparent 32%),
          linear-gradient(180deg, #fffdf7, #fef4db);
      }

      .hero-card h1,
      .panel-title strong,
      .mini-panel h3 {
        margin: 0;
        font-family: "Space Grotesk", Inter, sans-serif;
        letter-spacing: -0.04em;
      }

      .hero-card h1 {
        font-size: clamp(30px, 4vw, 48px);
        line-height: 0.98;
      }

      .hero-card p {
        margin: 12px 0 0;
        max-width: 70ch;
        color: var(--muted);
        line-height: 1.65;
      }

      .hero-actions {
        display: flex;
        flex-wrap: wrap;
        gap: 10px;
        margin-top: 18px;
      }

      .primary-button,
      .secondary-button,
      .convert-button {
        height: 46px;
        padding: 0 16px;
        font-weight: 800;
      }

      .primary-button,
      .convert-button {
        background: var(--accent);
      }

      .hero-aside {
        display: grid;
        gap: 12px;
      }

      .mini-panel {
        padding: 16px;
        background: linear-gradient(180deg, #fffdf7, #f4ffe7);
      }

      .mini-metric {
        display: flex;
        justify-content: space-between;
        align-items: baseline;
        gap: 10px;
        margin-top: 12px;
      }

      .mini-metric strong,
      .stat-value {
        font-family: "Space Grotesk", Inter, sans-serif;
        letter-spacing: -0.05em;
      }

      .mini-metric strong {
        font-size: 28px;
      }

      .mini-metric span,
      .stat-sub,
      .panel-title span,
      .section-label,
      .bar-label,
      .footer-row,
      .sys-top,
      .action-row span {
        color: var(--muted);
      }

      .mini-bars,
      .sys-grid,
      .actions-list {
        display: grid;
        gap: 10px;
      }

      .bar-row,
      .sys-item {
        display: grid;
        gap: 6px;
      }

      .bar-label,
      .sys-top {
        display: flex;
        justify-content: space-between;
        align-items: center;
        font-size: 12px;
      }

      .bar,
      .sys-bar {
        height: 10px;
        border: 2px solid #111;
        border-radius: 999px;
        background: #ece3d5;
        overflow: hidden;
      }

      .stats-grid {
        display: grid;
        grid-template-columns: repeat(6, minmax(0, 1fr));
        gap: 14px;
      }

      .stat-card {
        padding: 16px;
        min-height: 118px;
        background: linear-gradient(180deg, #fffdf8, #f4f0e8);
      }

      .stat-header {
        display: flex;
        justify-content: space-between;
        gap: 12px;
        align-items: flex-start;
      }

      .stat-label {
        font-size: 11px;
        text-transform: uppercase;
        letter-spacing: 0.12em;
        color: var(--muted);
      }

      .stat-value {
        margin-top: 10px;
        font-size: 28px;
        line-height: 1;
      }

      .stat-sub {
        margin-top: 10px;
        font-size: 12px;
      }

      .stat-sub strong {
        color: var(--success);
      }

      .stat-icon {
        width: 38px;
        height: 38px;
        border: 3px solid #111;
        border-radius: 12px;
        display: grid;
        place-items: center;
        background: var(--accent-2);
        color: #111;
        font-size: 18px;
      }

      .section-grid {
        display: grid;
        grid-template-columns: 1.25fr 1.05fr 0.9fr;
        gap: 14px;
      }

      .panel {
        overflow: hidden;
        background: var(--panel-strong);
      }

      .panel-head,
      .preview-toolbar {
        display: flex;
        justify-content: space-between;
        align-items: center;
        gap: 12px;
        padding: 14px 16px;
        border-bottom: 3px solid #111;
        background: linear-gradient(180deg, #fff, #faf2e0);
      }

      .panel-title {
        display: flex;
        flex-direction: column;
        gap: 4px;
      }

      .panel-title strong {
        font-size: 15px;
      }

      .panel-title span {
        font-size: 12px;
      }

      .link-button,
      .small-button {
        height: 34px;
        padding: 0 12px;
        font-size: 12px;
        font-weight: 800;
      }

      .table-wrap {
        overflow: auto;
      }

      table {
        width: 100%;
        border-collapse: collapse;
      }

      th,
      td {
        padding: 12px 16px;
        text-align: left;
        border-bottom: 2px solid rgba(18, 18, 18, 0.12);
        white-space: nowrap;
      }

      th {
        font-size: 11px;
        text-transform: uppercase;
        letter-spacing: 0.12em;
        background: #fbf6ea;
      }

      td {
        font-size: 13px;
      }

      tbody tr:hover {
        background: rgba(255, 191, 31, 0.12);
      }

      .source-link {
        color: #111;
        font-weight: 800;
      }

      .pill {
        display: inline-flex;
        align-items: center;
        gap: 6px;
        padding: 5px 10px;
        border: 2px solid #111;
        border-radius: 999px;
        font-size: 12px;
        font-weight: 800;
      }

      .pill.good {
        background: var(--accent-2);
      }

      .pill.mid {
        background: var(--accent);
      }

      .pill.bad {
        background: var(--accent-3);
      }

      .pill.neutral {
        background: #fff;
      }

      .converter {
        display: grid;
        grid-template-columns: 1.1fr 0.8fr 1.45fr;
        gap: 14px;
      }

      .code-panel,
      .controls-panel,
      .preview-panel {
        min-height: 470px;
      }

      .code-box {
        height: 100%;
        margin: 0;
        padding: 18px 20px;
        background: #111;
        color: #f9f1df;
        font-family: SFMono-Regular, Consolas, "Liberation Mono", Menlo, monospace;
        font-size: 12px;
        line-height: 1.7;
        overflow: auto;
      }

      .code-line {
        display: grid;
        grid-template-columns: 32px minmax(0, 1fr);
        gap: 12px;
      }

      .line-no {
        color: rgba(249, 241, 223, 0.45);
        text-align: right;
        user-select: none;
      }

      .syntax-key {
        color: #ffbf1f;
      }

      .syntax-str {
        color: #66f0c2;
      }

      .syntax-num {
        color: #ffd166;
      }

      .controls-panel {
        padding: 16px;
        display: grid;
        gap: 12px;
        align-content: start;
        background: linear-gradient(180deg, #fffdf8, #fff4d5);
      }

      .field {
        display: grid;
        gap: 6px;
      }

      .field label,
      .setting-label {
        font-size: 12px;
        color: var(--muted);
        font-weight: 700;
      }

      .select,
      .input,
      .more-options {
        width: 100%;
        border: 3px solid #111;
        border-radius: 12px;
        background: #fff;
        height: 42px;
        padding: 0 12px;
        color: var(--ink);
        box-shadow: 3px 3px 0 #111;
      }

      .setting-box {
        padding: 12px;
        border: 3px solid #111;
        border-radius: 14px;
        background: #fff;
        display: grid;
        gap: 10px;
      }

      .checkbox-row {
        display: flex;
        align-items: center;
        gap: 10px;
        color: var(--ink);
        font-size: 13px;
        font-weight: 600;
      }

      .checkbox-row input {
        width: 16px;
        height: 16px;
        accent-color: var(--accent);
      }

      .preview-panel {
        display: grid;
        grid-template-rows: auto 1fr auto;
        background: #fff;
      }

      .preview-table {
        overflow: auto;
      }

      .footer-row-2 {
        display: flex;
        justify-content: space-between;
        align-items: center;
        gap: 12px;
        padding: 12px 16px 16px;
        border-top: 3px solid #111;
        font-size: 12px;
        color: var(--muted);
      }

      .pagination {
        display: inline-flex;
        align-items: center;
        gap: 6px;
      }

      .page {
        min-width: 32px;
        height: 32px;
        padding: 0 8px;
        border: 2px solid #111;
        border-radius: 10px;
        display: inline-grid;
        place-items: center;
        background: #fff;
        font-size: 12px;
        font-weight: 800;
      }

      .page.active {
        background: var(--accent);
      }

      .bottom-grid {
        display: grid;
        grid-template-columns: 0.9fr 0.95fr 1.2fr 0.75fr;
        gap: 14px;
      }

      .format-grid {
        display: grid;
        grid-template-columns: repeat(3, 1fr);
        gap: 10px;
      }

      .format-card {
        border: 3px solid #111;
        border-radius: 16px;
        background: #fff;
        padding: 14px 12px;
        text-align: center;
        box-shadow: 4px 4px 0 #111;
      }

      .format-icon {
        width: 36px;
        height: 36px;
        margin: 0 auto 8px;
        border: 3px solid #111;
        border-radius: 12px;
        display: grid;
        place-items: center;
        background: var(--accent-2);
        color: #111;
        font-size: 16px;
      }

      .action-row {
        display: flex;
        justify-content: space-between;
        align-items: center;
        gap: 10px;
        padding: 12px 14px;
        border: 3px solid #111;
        border-radius: 14px;
        background: #fff;
      }

      .action-row strong {
        display: block;
        font-size: 13px;
      }

      .sys-item {
        display: grid;
        gap: 6px;
      }

      .reveal {
        animation: rise 650ms ease both;
      }

      @keyframes rise {
        from {
          opacity: 0;
          transform: translateY(14px);
        }
        to {
          opacity: 1;
          transform: translateY(0);
        }
      }

      @media (max-width: 1380px) {
        .hero,
        .section-grid,
        .converter,
        .bottom-grid {
          grid-template-columns: 1fr;
        }

        .stats-grid {
          grid-template-columns: repeat(3, minmax(0, 1fr));
        }
      }

      @media (max-width: 980px) {
        .app {
          grid-template-columns: 1fr;
        }

        .sidebar {
          position: relative;
          height: auto;
        }

        .stats-grid {
          grid-template-columns: repeat(2, minmax(0, 1fr));
        }

        .topbar {
          flex-direction: column;
          align-items: stretch;
        }

        .topbar-left,
        .topbar-right {
          justify-content: space-between;
          flex-wrap: wrap;
        }
      }

      @media (max-width: 680px) {
        .main {
          padding: 10px;
        }

        .content {
          padding: 10px;
        }

        .stats-grid,
        .format-grid {
          grid-template-columns: 1fr;
        }

        .icon-button,
        .text-button,
        .primary-button,
        .secondary-button,
        .link-button,
        .small-button,
        .convert-button {
          width: 100%;
          justify-content: center;
        }
      }
